import React from 'react';
import { Menu, Grid } from 'antd';
import { NavLink } from 'react-router-dom';
import { LoginOutlined } from '@ant-design/icons';
import { connect, ConnectedProps } from 'react-redux';
import { PATH } from 'src/constants/paths';

const { useBreakpoint } = Grid;

const mapStateToProps = (state: AppState) => ({
  isAuthenticated: state.auth.isAuthenticated,
  user: state.auth.user as IUser,
});
const connector = connect(mapStateToProps);
interface Props extends ConnectedProps<typeof connector> {}

const _RightMenu = (props: Props) => {
  const { isAuthenticated, user } = props;
  const { md } = useBreakpoint();
  const guestLinks = (
    <Menu mode={md ? 'horizontal' : 'inline'}>
      <Menu.Item key="menukey-login">
        <a className="navbar-item primary" href="/.auth/login/aad">
          Sign In
        </a>
      </Menu.Item>
    </Menu>
  );
  const authLinks = (
    <Menu mode={md ? 'horizontal' : 'inline'}>
      <Menu.Item key="menukey-profile">
        <NavLink className="navbar-item primary" to={PATH.PROFILE}>
          Hi <strong>{user.username}</strong>
        </NavLink>
      </Menu.Item>
      <Menu.Item key="menukey-logout">
        <a className="navbar-item primary" href="/.auth/logout">
          <span>
            <LoginOutlined />
            Log Out
          </span>
        </a>
      </Menu.Item>
    </Menu>
  );
  return <>{isAuthenticated ? authLinks : guestLinks}</>;
};

const RightMenu = connector(_RightMenu);
export { RightMenu };
